'use client';
import { useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

interface Props {
  open: boolean;
  onClose: () => void;
}

const CALENDLY_URL = 'https://calendly.com/iosdivyesh/30min';

export default function MeetingScheduler({ open, onClose }: Props) {
  useEffect(() => {
    document.body.style.overflow = open ? 'hidden' : '';
    return () => { document.body.style.overflow = ''; };
  }, [open]);

  useEffect(() => {
    if (!open) return;
    const script = document.createElement('script');
    script.src = 'https://assets.calendly.com/assets/external/widget.js';
    script.async = true;
    document.head.appendChild(script);
    return () => {
      const existing = document.querySelector('script[src*="calendly"]');
      if (existing) existing.remove();
    };
  }, [open]);

  return (
    <AnimatePresence>
      {open && (
        <>
          <motion.div
            className="sched-overlay"
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            onClick={onClose}
          />
          <motion.div
            className="sched-modal sched-modal-calendly"
            initial={{ y: '100%', opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: '100%', opacity: 0 }}
            transition={{ type: 'spring', stiffness: 280, damping: 28 }}
          >
            <div className="sched-header">
              <div className="sched-header-left">
                <div className="sched-icon">📅</div>
                <div>
                  <h3 className="sched-title">Book a Free 30-min Call</h3>
                  <p className="sched-subtitle">Pick a slot · Calendly · Confirmation sent to your email</p>
                </div>
              </div>
              <button className="sched-close" onClick={onClose}>✕</button>
            </div>

            <div className="sched-calendly-body">
              <div
                className="calendly-inline-widget"
                data-url={`${CALENDLY_URL}?hide_gdpr_banner=1&primary_color=d4a03a`}
