'use client';
import { useState, useRef, useEffect } from 'react';

const COLORS = ['gold', 'emerald', 'sapphire', 'rose', 'violet', 'copper'] as const;
type Color = typeof COLORS[number];

export default function ThemePanel() {
  const [open, setOpen] = useState(false);
  const [activeColor, setActiveColor] = useState<Color>('gold');
  const [activeMode, setActiveMode] = useState<'dark' | 'light'>('dark');
  const panelRef = useRef<HTMLDivElement>(null);

  const setColor = (c: Color) => {
    document.documentElement.dataset.color = c;
    setActiveColor(c);
  };
  const setMode = (m: 'dark' | 'light') => {
    document.documentElement.dataset.theme = m;
    setActiveMode(m);
  };

  useEffect(() => {
    if (!open) return;
    const handler = (e: MouseEvent) => {
      if (panelRef.current && !panelRef.current.contains(e.target as Node)) {
        setOpen(false);
      }
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [open]);

  return (
    <div id="theme-panel" className={open ? 'open' : ''} ref={panelRef}>
      <button id="theme-toggle-btn" onClick={() => setOpen(v => !v)}>Themes</button>
      <h4>Colour Theme</h4>
      <div className="color-grid">
        {COLORS.map(c => (
          <button
            key={c}
            className={`color-swatch${activeColor === c ? ' active' : ''}`}
            data-c={c}
            onClick={() => setColor(c)}
          >
            <span>{c}</span>
          </button>
        ))}
      </div>
      <h4 style={{ marginTop: '0.5rem' }}>Mode</h4>
      <div className="mode-toggle">
        <button className={`mode-btn${activeMode === 'dark' ? ' active' : ''}`} data-mode="dark" onClick={() => setMode('dark')}>🌙 Dark</button>
        <button className={`mode-btn${activeMode === 'light' ? ' active' : ''}`} data-mode="light" onClick={() => setMode('light')}>☀️ Light</button>
      </div>
    </div>
  );
}

'use client';
import { useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import dynamic from 'next/dynamic';

const IncomeTaxCalc = dynamic(() => import('./tools/IncomeTaxCalc'), { ssr: false });
const GSTCalc = dynamic(() => import('./tools/GSTCalc'), { ssr: false });
const BusinessValuation = dynamic(() => import('./tools/BusinessValuation'), { ssr: false });
const ComplianceCalendar = dynamic(() => import('./tools/ComplianceCalendar'), { ssr: false });
const ITCChecker = dynamic(() => import('./tools/ITCChecker'), { ssr: false });
const AuditRisk = dynamic(() => import('./tools/AuditRisk'), { ssr: false });

const TOOLS = [
  { id: 'tax', icon: '📊', name: 'Income Tax Calculator', subtitle: 'FY 2025–26 · Old vs New Regime', component: <IncomeTaxCalc /> },
  { id: 'gst', icon: '🧾', name: 'GST Calculator', subtitle: 'CGST · SGST · IGST · Inclusive / Exclusive', component: <GSTCalc /> },
  { id: 'valuation', icon: '📉', name: 'Business Valuation', subtitle: 'DCF · WACC · Terminal Value · Sensitivity', component: <BusinessValuation /> },
  { id: 'calendar', icon: '📅', name: 'Compliance Calendar', subtitle: 'GST · IT · TDS · ROC Deadlines FY 2025–26', component: <ComplianceCalendar /> },
  { id: 'itc', icon: '🔍', name: 'ITC Eligibility Checker', subtitle: 'Section 17(5) · Blocked Credits Reference', component: <ITCChecker /> },
  { id: 'audit', icon: '🏦', name: 'Audit Risk Assessment', subtitle: 'Risk Scoring · Materiality Calculation', component: <AuditRisk /> },
];

interface Props {
  toolId: string | null;
  onClose: () => void;
  onNavigate: (id: string) => void;
}

export default function CalculatorModal({ toolId, onClose }: Props) {
  const tool = TOOLS.find(t => t.id === toolId);
  const wrapperRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => { if (e.key === 'Escape') onClose(); };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [onClose]);

  // Scroll the inline section into view when a tool opens
  useEffect(() => {
    if (toolId && wrapperRef.current) {
      setTimeout(() => {
        wrapperRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }, 80);
    }
  }, [toolId]);

  return (
    <div ref={wrapperRef}>
      <AnimatePresence>
        {toolId && tool && (
          <motion.div
            className="calc-inline"
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            transition={{ duration: 0.35, ease: 'easeInOut' }}
            style={{ overflow: 'hidden' }}
          >
            {/* Top bar */}
            <div className="calc-fs-topbar">
              <button className="calc-fs-back" onClick={onClose}>
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M19 12H5M12 5l-7 7 7 7" />
                </svg>
                Back to Tools
              </button>

              <div className="calc-fs-title">
                <span className="calc-fs-icon">{tool.icon}</span>
                <div>
                  <div className="calc-fs-name">{tool.name}</div>
                  <div className="calc-fs-sub">{tool.subtitle}</div>
                </div>
              </div>

              <button className="calc-fs-esc" onClick={onClose}>ESC</button>
            </div>

            {/* Tool content */}
            <div className="calc-fs-body">
              {tool.component}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

